module top_module(obf_A, B, ALUCtr, ALUOut);input [31:0] obf_A, B;
		input [2:0] ALUCtr;
		output [31:0] ALUOut;	

		assign ALUOut = (ALUCtr == 3'b000) ? obf_A&B :
										  (ALUCtr == 3'b001) ? obf_A|B :
										  (ALUCtr == 3'b010) ? obf_A+B :
										  (ALUCtr == 3'b011) ? obf_A-B :
										  (ALUCtr == 3'b100) ? $signed($signed(B)>>>obf_A[4:0]) :
										  32'b0;

endmodule
